{
  "name": "hello-rainbow-ui-req",
  "version": "0.1.0",
  "private": true,
  "description": "Requirements doc and tests for a Hello World rainbow UI",
  "scripts": {
    "test": "jest"
  },
  "devDependencies": {
    "@types/jest": "^29.5.3",
    "jest": "^29.6.0",
    "ts-jest": "^29.1.0",
    "typescript": "^5.2.2"
  }
}

// Placeholder module for the requirements subtask.
// No UI implementation is included in this subtask.
export const requirementsPath = 'docs/requirements.md';

import { readFileSync } from 'fs';
import { join } from 'path';

describe('requirements document', () => {
  const path = join(__dirname, '..', 'docs', 'requirements.md');
  let contents: string;

  beforeAll(() => {
    contents = readFileSync(path, 'utf8');
  });

  test('contains the exact visible text Hello World', () => {
    expect(contents).toMatch(/Hello World/);
  });

  test('mentions prefers-reduced-motion', () => {
    expect(contents.toLowerCase()).toContain('prefers-reduced-motion');
  });

  test('includes at least one rainbow hex color (e.g., #FF0000)', () => {
    const hexPattern = /#([A-Fa-f0-9]{6})/g;
    const matches = contents.match(hexPattern) || [];
    expect(matches.length).toBeGreaterThanOrEqual(1);
  });

  test('contains a success criteria section mentioning acceptance tests', () => {
    expect(contents).toMatch(/Success criteria/i);
    expect(contents).toMatch(/acceptance tests?/i);
  });
});
